package com.samudhra.certificates.controller;
import com.fasterxml.jackson.databind.ObjectMapper; import com.samudhra.certificates.dto.ApiResponse; import com.samudhra.certificates.entity.*; import com.samudhra.certificates.repository.*; import com.samudhra.certificates.service.CurrentUserService; import org.springframework.web.bind.annotation.*; import org.springframework.transaction.annotation.Transactional; import java.time.LocalDate; import java.util.*;
@RestController @RequestMapping("/api/certificates") @Transactional public class CertificateController {private final CertificateRepository certificates;private final StudentRepository students;private final TemplateRepository templates;private final CurrentUserService current;private final ObjectMapper json;public CertificateController(CertificateRepository c,StudentRepository s,TemplateRepository t,CurrentUserService u,ObjectMapper j){certificates=c;students=s;templates=t;current=u;json=j;}@PostMapping("/generate") public ApiResponse<?> generate(@RequestBody Map<String,Object>b)throws Exception{Student student=students.findById((String)b.get("studentId")).orElseThrow(()->new NoSuchElementException("Student not found"));Template template=templates.findById((String)b.get("templateId")).orElseThrow(()->new NoSuchElementException("Template not found"));if(!student.getOrganization().getId().equals(current.organization().getId())||!template.getOrganization().getId().equals(current.organization().getId()))throw new NoSuchElementException("Record not found");Certificate c=new Certificate();c.setOrganization(current.organization());c.setStudent(student);c.setTemplate(template);c.setCertificateNumber((String)b.get("certificateNumber"));c.setIssueDate(b.get("issueDate")==null?LocalDate.now():LocalDate.parse((String)b.get("issueDate")));c.setSnapshotJson(json.writeValueAsString(b.getOrDefault("templateSnapshot",Map.of())));return ApiResponse.ok(view(certificates.save(c)));}@GetMapping public ApiResponse<?> list(){return ApiResponse.ok(certificates.findAll().stream().filter(c->c.getOrganization().getId().equals(current.organization().getId())).map(this::view).toList());}@GetMapping("/verify/{certificateNumber}") public ApiResponse<?> verify(@PathVariable String certificateNumber){List<Certificate> matches=certificates.findByCertificateNumberOrStudentName(certificateNumber);if(matches.isEmpty())throw new NoSuchElementException("Certificate not found");return ApiResponse.ok(view(matches.get(0)));}private Map<String,Object> view(Certificate c){Map<String,Object>m=new LinkedHashMap<>();m.put("id",c.getId());m.put("certificateNumber",c.getCertificateNumber());m.put("issueDate",c.getIssueDate());m.put("status",c.getStatus());m.put("studentName",c.getStudent().getName());m.put("course",c.getStudent().getCourse());m.put("company",c.getOrganization().getName());m.put("templateId",c.getTemplate().getId());try{m.put("templateSnapshot",c.getSnapshotJson()!=null?json.readValue(c.getSnapshotJson(),Map.class):Map.of());}catch(Exception e){m.put("templateSnapshot",Map.of());}return m;}}
